import{_ as e,o as l,c as a,a3 as r}from"./chunks/framework.BTFg6ESq.js";const u=JSON.parse('{"title":"对话树图 (Tree Graph)","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/sessions/tree-graph.md","filePath":"user-guide/tools/llm-chat/sessions/tree-graph.md","lastUpdated":1778239080000}'),o={name:"user-guide/tools/llm-chat/sessions/tree-graph.md"};function i(s,t,n,d,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="对话树图-tree-graph" tabindex="-1">对话树图 (Tree Graph) <a class="header-anchor" href="#对话树图-tree-graph" aria-label="Permalink to &quot;对话树图 (Tree Graph)&quot;">​</a></h1><p>对话树图是 LLM Chat 的核心特性之一，它将线性的对话历史转变为可视化的拓扑结构。通过树图，您可以直观地查看、管理和操作复杂的对话分支。</p><h2 id="_1-视图切换" tabindex="-1">1. 视图切换 <a class="header-anchor" href="#_1-视图切换" aria-label="Permalink to &quot;1. 视图切换&quot;">​</a></h2><p>在对话区域的工具栏中，您可以随时在 <strong>线性列表视图</strong> 和 <strong>树图视图</strong> 之间切换：</p><ul><li><strong>线性列表</strong>：适合阅读长篇对话，侧重于当前分支的上下文连贯性。</li><li><strong>树图视图</strong>：适合管理多分支探索，侧重于对话的结构化组织和非线性跳转。</li></ul><h2 id="_2-布局模式" tabindex="-1">2. 布局模式 <a class="header-anchor" href="#_2-布局模式" aria-label="Permalink to &quot;2. 布局模式&quot;">​</a></h2><p>树图支持三种不同的布局算法，以适应不同的使用场景：</p><table tabindex="0"><thead><tr><th style="text-align:left;">模式</th><th style="text-align:left;">说明</th><th style="text-align:left;">适用场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>动态树状 (Tree)</strong></td><td style="text-align:left;">确定性的层级排列，结合物理碰撞防止节点重叠。</td><td style="text-align:left;">结构清晰的对话，层级关系明确。</td></tr><tr><td style="text-align:left;"><strong>物理引力 (Physics)</strong></td><td style="text-align:left;">基于 D3-force 的力导向布局，带有模拟重力。</td><td style="text-align:left;">探索性对话，节点分布更自然。</td></tr><tr><td style="text-align:left;"><strong>静态树状 (Static)</strong></td><td style="text-align:left;">纯几何计算布局，不包含物理模拟。</td><td style="text-align:left;">节点极多时的性能优化模式。</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>您可以在树图右侧的控制栏中点击布局图标（网格/分享/减号）循环切换模式，或在“视图设置”中指定默认布局。</p></div><h2 id="_3-节点操作" tabindex="-1">3. 节点操作 <a class="header-anchor" href="#_3-节点操作" aria-label="Permalink to &quot;3. 节点操作&quot;">​</a></h2><p>树图中的每个节点代表一条消息，您可以直接对其进行交互：</p><h3 id="基础交互" tabindex="-1">基础交互 <a class="header-anchor" href="#基础交互" aria-label="Permalink to &quot;基础交互&quot;">​</a></h3><ul><li><strong>单击选择</strong>：选中节点并在右侧或悬浮窗查看详情。</li><li><strong>双击跳转</strong>：将当前对话分支切换到该节点所在路径。</li><li><strong>右键菜单</strong>：提供“设为当前分支”、“禁用/启用节点”、“剪掉分支”等快捷操作。</li></ul><h3 id="拖拽与移动" tabindex="-1">拖拽与移动 <a class="header-anchor" href="#拖拽与移动" aria-label="Permalink to &quot;拖拽与移动&quot;">​</a></h3><ul><li><strong>单点拖拽</strong>：直接拖动节点可手动调整其位置。</li><li><strong>子树拖拽</strong>：按住修饰键（默认 <code>Shift</code>，可在设置中修改）拖动节点，将连带其所有子孙节点一起移动。</li><li><strong>重置布局</strong>：如果布局变得混乱，点击控制栏的“刷新”图标可一键重置到算法初始位置。</li></ul><h3 id="分支嫁接-grafting" tabindex="-1">分支嫁接 (Grafting) <a class="header-anchor" href="#分支嫁接-grafting" aria-label="Permalink to &quot;分支嫁接 (Grafting)&quot;">​</a></h3><p>这是树图最高级的操作之一。您可以改变对话的历史逻辑：</p><ol><li>从一个节点的底部连接点按住并拖出连线。</li><li>将连线指向另一个节点。</li><li><strong>单点移动</strong>：仅将该节点移动到新父节点下。</li><li><strong>子树嫁接</strong>：按住修饰键（默认 <code>Shift</code>）进行连接，将整个子树整体迁移到新分支。</li></ol><h2 id="_4-历史面板-history-panel" tabindex="-1">4. 历史面板 (History Panel) <a class="header-anchor" href="#_4-历史面板-history-panel" aria-label="Permalink to &quot;4. 历史面板 (History Panel)&quot;">​</a></h2><p>树图的操作是<strong>非破坏性</strong>的，所有结构变更都会记录在会话历史中。</p><ul><li><strong>撤销/重做</strong>：支持对节点编辑、移动、嫁接、删除等操作进行无限次撤销（快捷键 <code>Ctrl+Z</code> / <code>Ctrl+Y</code>）。</li><li><strong>查看历史</strong>：点击控制栏的“时钟”图标打开历史面板。</li><li><strong>操作类型</strong>： <ul><li><code>BRANCH_GRAFT</code>：分支嫁接</li><li><code>NODE_MOVE</code>：节点移动</li><li><code>NODE_EDIT</code>：内容编辑</li><li><code>NODE_TOGGLE_ENABLED</code>：启用/禁用切换</li></ul></li><li><strong>状态快照</strong>：历史面板会显示每次操作影响的节点数，并允许您一键跳转回任意历史状态。</li></ul><h2 id="_5-辅助功能" tabindex="-1">5. 辅助功能 <a class="header-anchor" href="#_5-辅助功能" aria-label="Permalink to &quot;5. 辅助功能&quot;">​</a></h2><ul><li><strong>HUD 信息面板</strong>：显示当前 FPS、节点总数、布局模式和缩放比例。</li><li><strong>小地图 (MiniMap)</strong>：在节点过多时辅助导航。</li><li><strong>自动定位</strong>：点击控制栏的“准星”图标，视口将自动平滑滚动并对齐到当前激活的叶子节点。</li><li><strong>调试模式</strong>：为高级用户提供，显示 D3 物理引擎的力向量、速度和节点状态数据。</li></ul><hr><p><strong>相关阅读</strong>：</p><ul><li><a href="./">消息管理</a></li><li><a href="./../agents/assets">Agent 资产</a></li><li><a href="./../macro-system/">宏系统</a></li></ul>',26)])])}const p=e(o,[["render",i]]);export{u as __pageData,p as default};
